import { useMemo } from "react";
import { Link } from "react-router-dom";
import Header from "@/components/landing/Header";
import Footer from "@/components/landing/Footer";
import { useMarket } from "@/lib/MarketContext";
import { fmt } from "@/lib/parseItem";
import { TrendingUp, TrendingDown, DollarSign, ShoppingCart, Percent } from "lucide-react";
import { ResponsiveContainer, BarChart, PieChart, LineChart, Bar, Pie, Line, XAxis, YAxis, Tooltip, Cell } from "recharts";

export default function DashboardPage() {
  const { market, loading, error } = useMarket();

const COLORS = ['#10b981', '#3b82f6', '#f59e0b', '#ef4444', '#8b5cf6', '#06b6d4', '#ec4899'];

const metrics = useMemo(() => {
  if (!market?.rows) return null;
  const stats = market.stats;
  const total = stats.totalItems;
  const priced = stats.pricedItems;
  const healthPct = Math.round((priced / total) * 100) || 0;
  const confidencePct = Math.round((stats.highConfidence / priced) * 100) || 0;
  const rising = stats.risingItems;

  const trendCounts = { up: 0, down: 0, stable: 0 };
  market.rows.forEach(r => {
    if (r.trend === "up") trendCounts.up++;
    else if (r.trend === "down") trendCounts.down++;
    else trendCounts.stable++;
  });

  // Price distribution data
  const priceRanges = [
    { range: "<10k", min: 0, max: 10000, count: 0 },
    { range: "10k-100k", min: 10000, max: 100000, count: 0 },
    { range: "100k-1M", min: 100000, max: 1000000, count: 0 },
    { range: "1M-10M", min: 1000000, max: 10000000, count: 0 },
    { range: "10M-100M", min: 10000000, max: 100000000, count: 0 },
    { range: ">100M", min: 100000000, count: 0 }
  ];

  market.rows.forEach(row => {
    if (row.median > 0) {
      if (row.median < 10000) priceRanges[0].count++;
      else if (row.median < 100000) priceRanges[1].count++;
      else if (row.median < 1000000) priceRanges[2].count++;
      else if (row.median < 10000000) priceRanges[3].count++;
      else if (row.median < 100000000) priceRanges[4].count++;
      else priceRanges[5].count++;
    }
  });

  // Volume trends data (simulated for demo)
  const volumeTrendsData = [
    { time: '1d', volume: 1200 },
    { time: '3d', volume: 1800 },
    { time: '7d', volume: 2500 },
    { time: '14d', volume: 3200 },
    { time: '30d', volume: 4500 },
  ];

  // Markup analysis data
  const markupAnalysisData = [
    { name: '<10%', value: stats.lowMarkup || 0 },
    { name: '10-25%', value: stats.mediumMarkup || 0 },
    { name: '25-50%', value: stats.highMarkup || 0 },
    { name: '50-100%', value: stats.veryHighMarkup || 0 },
    { name: '>100%', value: stats.extremeMarkup || 0 },
  ];

  return {
    total,
    priced,
    healthPct,
    confidencePct,
    rising,
    trendCounts,
    priceDistributionData: priceRanges,
    volumeTrendsData,
    markupAnalysisData,
  };
}, [market]);

  const {
    priceDistributionData,
    volumeTrendsData,
    markupAnalysisData,
    total,
    priced,
    healthPct,
    confidencePct,
    rising,
    trendCounts,
  } = metrics || {};

  if (loading.market || !metrics) {
    return (
      <div className="min-h-screen bg-bg-base text-white">
        <Header />
        <main className="pt-32 pb-24">
          <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
            <div className="text-zinc-400">Loading market data...</div>
          </div>
        </main>
      </div>
    );
  }

  return (
    <div className="min-h-screen bg-bg-base text-white">
      <Header />
      <main className="pt-32 pb-24">
        <div className="max-w-7xl mx-auto px-6 md:px-12 lg:px-16">
          <div className="font-mono text-[11px] uppercase tracking-[0.25em] text-emerald-400 mb-4">/ Market Dashboard</div>
          <h1 className="font-heading text-5xl lg:text-7xl tracking-tighter font-black leading-[0.95] mb-8">
            Market <span className="text-emerald-400">Health</span>
          </h1>

           <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6 mb-8">
             <div className="bg-white/[0.02] border border-white/10 rounded-lg p-5">
               <div className="text-[10px] uppercase tracking-wider text-zinc-500 mb-2">Total Items</div>
               <div className="text-3xl font-heading font-bold">{total}</div>
             </div>
             <div className="bg-white/[0.02] border border-white/10 rounded-lg p-5">
               <div className="text-[10px] uppercase tracking-wider text-zinc-500 mb-2">Priced Items</div>
               <div className="text-3xl font-heading font-bold">{priced}</div>
               <div className="text-[11px] text-zinc-400 mt-1">{healthPct}% coverage</div>
             </div>
             <div className="bg-white/[0.02] border border-white/10 rounded-lg p-5">
               <div className="text-[10px] uppercase tracking-wider text-zinc-500 mb-2">High Confidence</div>
               <div className="text-3xl font-heading font-bold">{confidencePct}%</div>
               <div className="text-[11px] text-zinc-400 mt-1">{market.stats.highConfidence} items</div>
             </div>
             <div className="bg-white/[0.02] border border-white/10 rounded-lg p-5">
               <div className="text-[10px] uppercase tracking-wider text-zinc-500 mb-2">Rising Prices</div>
               <div className="text-3xl font-heading font-bold text-emerald-400">{rising}</div>
               <div className="text-[11px] text-zinc-400 mt-1">Last updated: {market.stats.lastUpdated}</div>
             </div>
           </div>

          <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-8">
             <div className="bg-white/[0.02] border border-white/10 rounded-lg p-5">
               <div className="text-[10px] uppercase tracking-wider text-zinc-500 mb-4 font-mono">Price Trends</div>
               <div className="grid grid-cols-3 gap-4">
                 <div className="text-center">
                   <div className="text-2xl font-bold text-emerald-400">{trendCounts.up}</div>
                   <div className="text-[11px] text-zinc-400 flex items-center justify-center gap-1 mt-1">
                     <TrendingUp className="w-3 h-3" /> Rising
                   </div>
                 </div>
                 <div className="text-center">
                   <div className="text-2xl font-bold text-red-400">{trendCounts.down}</div>
                   <div className="text-[11px] text-zinc-400 flex items-center justify-center gap-1 mt-1">
                     <TrendingDown className="w-3 h-3" /> Falling
                   </div>
                 </div>
                 <div className="text-center">
                   <div className="text-2xl font-bold text-zinc-300">{trendCounts.stable}</div>
                   <div className="text-[11px] text-zinc-400 mt-1">Stable</div>
                 </div>
               </div>
             </div>

            <div className="bg-white/[0.02] border border-white/10 rounded-lg p-5">
              <div className="text-[10px] uppercase tracking-wider text-zinc-500 mb-4 font-mono">Category Breakdown</div>
              <div className="space-y-2">
                {market.categoryBreakdown.slice(0, 5).map((c) => (
                  <div key={c.name} className="flex items-center gap-3">
                    <div className="w-2 h-2 rounded-full" style={{ backgroundColor: c.color }}></div>
                    <div className="flex-1 text-sm font-mono">{c.name}</div>
                    <div className="text-right">
                      <div className="text-sm font-mono">{c.value}</div>
                      <div className="text-[10px] text-zinc-500">{c.pct}%</div>
                    </div>
                  </div>
                ))}
              </div>
            </div>
          </div>

           <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 mb-8">
             {/* Price Distribution Chart */}
             <div className="bg-white/[0.02] border border-white/10 rounded-lg p-5">
               <div className="flex items-center gap-2 mb-4">
                 <DollarSign className="w-4 h-4 text-emerald-400" />
                 <div className="text-[10px] uppercase tracking-wider text-zinc-500 font-mono">Price Distribution</div>
               </div>
               <div className="h-64">
                 <ResponsiveContainer width="100%" height="100%">
                   <BarChart data={priceDistributionData}>
                     <XAxis dataKey="range" tick={{ fill: '#9ca3af', fontSize: 10 }} />
                     <YAxis tick={{ fill: '#9ca3af', fontSize: 10 }} />
                     <Tooltip
                       contentStyle={{ backgroundColor: '#1f2937', border: 'none' }}
                       labelStyle={{ color: '#d1d5db' }}
                       itemStyle={{ color: '#d1d5db' }}
                     />
                     <Bar dataKey="count" fill="#10b981" />
                   </BarChart>
                 </ResponsiveContainer>
               </div>
             </div>

             {/* Volume Trends Chart */}
             <div className="bg-white/[0.02] border border-white/10 rounded-lg p-5">
               <div className="flex items-center gap-2 mb-4">
                 <ShoppingCart className="w-4 h-4 text-emerald-400" />
                 <div className="text-[10px] uppercase tracking-wider text-zinc-500 font-mono">Volume Trends</div>
               </div>
               <div className="h-64">
                 <ResponsiveContainer width="100%" height="100%">
                   <LineChart data={volumeTrendsData}>
                     <XAxis dataKey="time" tick={{ fill: '#9ca3af', fontSize: 10 }} />
                     <YAxis tick={{ fill: '#9ca3af', fontSize: 10 }} />
                     <Tooltip
                       contentStyle={{ backgroundColor: '#1f2937', border: 'none' }}
                       labelStyle={{ color: '#d1d5db' }}
                       itemStyle={{ color: '#d1d5db' }}
                     />
                     <Line type="monotone" dataKey="volume" stroke="#10b981" strokeWidth={2} dot={false} />
                   </LineChart>
                 </ResponsiveContainer>
               </div>
             </div>
           </div>

           {/* Markup Analysis Chart */}
           <div className="bg-white/[0.02] border border-white/10 rounded-lg p-5 mb-8">
             <div className="flex items-center gap-2 mb-4">
               <Percent className="w-4 h-4 text-emerald-400" />
               <div className="text-[10px] uppercase tracking-wider text-zinc-500 font-mono">Markup Analysis</div>
             </div>
             <div className="h-64">
                 <ResponsiveContainer width="100%" height="100%">
                   <PieChart>
                     <Pie
                       data={markupAnalysisData}
                       cx="50%"
                       cy="50%"
                       labelLine={false}
                       outerRadius={80}
                       fill="#8884d8"
                       dataKey="value"
                       label={({ name, percent }) => `${name} ${(percent * 100).toFixed(0)}%`}
                     >
                       {markupAnalysisData.map((entry, index) => (
                         <Cell key={`cell-${index}`} fill={COLORS[index % COLORS.length]} />
                       ))}
                     </Pie>
                     <Tooltip
                       contentStyle={{ backgroundColor: '#1f2937', border: 'none' }}
                       labelStyle={{ color: '#d1d5db' }}
                       itemStyle={{ color: '#d1d5db' }}
                     />
                   </PieChart>
                 </ResponsiveContainer>
             </div>
           </div>

           <div className="bg-white/[0.02] border border-white/10 rounded-lg p-5 mb-8">
             <div className="text-[10px] uppercase tracking-wider text-zinc-500 mb-4 font-mono">Top Movers</div>
             <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
               {market.topMovers.slice(0, 4).map((item) => (
                 <Link
                   key={item.key}
                   to={`/item/${item.key}`}
                   className="bg-white/[0.01] border border-white/10 rounded p-3 hover:bg-white/[0.04] transition-colors"
                 >
                   <div className="text-sm font-mono truncate">{item.name}</div>
                   <div className="text-xs text-zinc-400 mt-1">{fmt(item.medianRaw)}</div>
                   <div className="text-[11px] mt-1">
                     <span className={item.trend === "up" ? "text-emerald-400" : item.trend === "down" ? "text-red-400" : "text-zinc-400"}>
                       {item.trend === "up" ? "↑" : item.trend === "down" ? "↓" : "—"} {item.trend}
                     </span>
                   </div>
                 </Link>
               ))}
             </div>
           </div>

          {error.market && (
            <div className="bg-red-500/10 border border-red-500/20 rounded-lg p-4 text-red-300">
              {error.market}
            </div>
          )}
        </div>
      </main>
      <Footer />
    </div>
  );
}